import os
import json
import pickle
import numpy as np
from flask import Flask, request, jsonify
from PIL import Image
import face_recognition
from sklearn.svm import SVC
from sklearn.preprocessing import LabelEncoder
from sklearn.calibration import CalibratedClassifierCV
import io
import base64
import glob
from datetime import datetime

app = Flask(__name__)

MODEL_PATH = "face_recognition_model.pkl"
ENCODER_PATH = "label_encoder.pkl"
TRAINING_DATA_DIR = "employee_photos"

model = None
label_encoder = None


def load_model():
    global model, label_encoder
    if os.path.exists(MODEL_PATH) and os.path.exists(ENCODER_PATH):
        with open(MODEL_PATH, "rb") as f:
            model = pickle.load(f)
        with open(ENCODER_PATH, "rb") as f:
            label_encoder = pickle.load(f)
        return True
    return False


def save_model():
    global model, label_encoder
    with open(MODEL_PATH, "wb") as f:
        pickle.dump(model, f)
    with open(ENCODER_PATH, "wb") as f:
        pickle.dump(label_encoder, f)


def get_face_encoding(image):
    """Extract face encoding from an image."""
    if image.mode != "RGB":
        image = image.convert("RGB")
    image_array = np.array(image)
    face_locations = face_recognition.face_locations(image_array, model="hog")
    if len(face_locations) == 0:
        return None, None
    face_encodings = face_recognition.face_encodings(image_array, face_locations)
    if len(face_encodings) == 0:
        return None, None
    return face_encodings, face_locations


def train_model_from_directory(data_dir):
    """
    Train model from directory structure:
    employee_photos/
        employee_name_1/
            photo1.jpg
            photo2.jpg
        employee_name_2/
            photo1.jpg
            photo2.jpg
    """
    global model, label_encoder

    encodings = []
    labels = []
    training_stats = {}

    if not os.path.exists(data_dir):
        os.makedirs(data_dir)
        return False, "Training data directory is empty. Add employee photos first.", {}

    employee_dirs = [
        d for d in os.listdir(data_dir)
        if os.path.isdir(os.path.join(data_dir, d))
    ]

    if len(employee_dirs) < 2:
        return False, "Need at least 2 employees to train the model.", {}

    for employee_name in employee_dirs:
        employee_dir = os.path.join(data_dir, employee_name)
        image_files = []
        for ext in ["*.jpg", "*.jpeg", "*.png", "*.bmp", "*.gif"]:
            image_files.extend(glob.glob(os.path.join(employee_dir, ext)))
            image_files.extend(glob.glob(os.path.join(employee_dir, ext.upper())))

        faces_found = 0
        for image_path in image_files:
            try:
                image = Image.open(image_path)
                face_encs, _ = get_face_encoding(image)
                if face_encs is not None:
                    for enc in face_encs:
                        encodings.append(enc)
                        labels.append(employee_name)
                        faces_found += 1
            except Exception as e:
                print(f"Error processing {image_path}: {e}")

        training_stats[employee_name] = {
            "total_images": len(image_files),
            "faces_detected": faces_found
        }

    if len(encodings) < 2:
        return False, "Not enough face encodings found in training data.", training_stats

    label_encoder = LabelEncoder()
    encoded_labels = label_encoder.fit_transform(labels)

    base_svm = SVC(kernel="rbf", probability=False, C=10.0, gamma="scale")
    model = CalibratedClassifierCV(base_svm, cv=min(3, min(np.bincount(encoded_labels))))

    model.fit(encodings, encoded_labels)
    save_model()

    return True, "Model trained successfully.", training_stats


@app.route("/api/train", methods=["POST"])
def train():
    """
    Train the facial recognition model.
    
    Can either:
    1. Train from the employee_photos directory (POST with no body or {"source": "directory"})
    2. Train from uploaded data (POST with JSON containing base64 encoded images)
    
    For directory-based training, organize photos as:
    employee_photos/<employee_name>/<photo_files>
    """
    data = request.get_json(silent=True) or {}
    source = data.get("source", "directory")

    if source == "directory":
        data_dir = data.get("data_dir", TRAINING_DATA_DIR)
        success, message, stats = train_model_from_directory(data_dir)
        return jsonify({
            "success": success,
            "message": message,
            "training_stats": stats,
            "num_classes": len(label_encoder.classes_.tolist()) if label_encoder is not None else 0,
            "classes": label_encoder.classes_.tolist() if label_encoder is not None else [],
            "timestamp": datetime.now().isoformat()
        }), 200 if success else 400

    elif source == "upload":
        # Expect {"source": "upload", "employees": {"name": ["base64_img1", "base64_img2"]}}
        employees_data = data.get("employees", {})
        if len(employees_data) < 2:
            return jsonify({
                "success": False,
                "message": "Need at least 2 employees to train."
            }), 400

        encodings = []
        labels = []
        training_stats = {}

        for employee_name, images_b64 in employees_data.items():
            faces_found = 0
            for img_b64 in images_b64:
                try:
                    img_bytes = base64.b64decode(img_b64)
                    image = Image.open(io.BytesIO(img_bytes))
                    face_encs, _ = get_face_encoding(image)
                    if face_encs is not None:
                        for enc in face_encs:
                            encodings.append(enc)
                            labels.append(employee_name)
                            faces_found += 1
                except Exception as e:
                    print(f"Error processing image for {employee_name}: {e}")

            training_stats[employee_name] = {
                "total_images": len(images_b64),
                "faces_detected": faces_found
            }

        if len(encodings) < 2:
            return jsonify({
                "success": False,
                "message": "Not enough faces detected.",
                "training_stats": training_stats
            }), 400

        global model, label_encoder
        label_encoder = LabelEncoder()
        encoded_labels = label_encoder.fit_transform(labels)

        base_svm = SVC(kernel="rbf", probability=False, C=10.0, gamma="scale")
        model = CalibratedClassifierCV(base_svm, cv=min(3, min(np.bincount(encoded_labels))))
        model.fit(encodings, encoded_labels)
        save_model()

        return jsonify({
            "success": True,
            "message": "Model trained successfully from uploaded data.",
            "training_stats": training_stats,
            "num_classes": len(label_encoder.classes_.tolist()),
            "classes": label_encoder.classes_.tolist(),
            "timestamp": datetime.now().isoformat()
        }), 200

    return jsonify({"success": False, "message": "Invalid source type."}), 400


@app.route("/api/recognize", methods=["POST"])
def recognize():
    """
    Recognize faces in an uploaded image.
    
    Accepts:
    - Multipart form with 'image' file
    - JSON with 'image' as base64 encoded string
    
    Returns confidence scores (probability distribution) for ALL known employees
    for each detected face.
    """
    global model, label_encoder

    if model is None or label_encoder is None:
        if not load_model():
            return jsonify({
                "success": False,
                "message": "Model not trained. Please train the model first via /api/train.",
                "faces": []
            }), 400

    image = None

    if "image" in request.files:
        file = request.files["image"]
        image = Image.open(file.stream)
    else:
        data = request.get_json(silent=True)
        if data and "image" in data:
            img_bytes = base64.b64decode(data["image"])
            image = Image.open(io.BytesIO(img_bytes))

    if image is None:
        return jsonify({
            "success": False,
            "message": "No image provided. Send as multipart 'image' or JSON base64.",
            "faces": []
        }), 400

    face_encodings, face_locations = get_face_encoding(image)

    if face_encodings is None:
        return jsonify({
            "success": True,
            "message": "No faces detected in the image.",
            "faces_detected": 0,
            "faces": [],
            "timestamp": datetime.now().isoformat()
        }), 200

    results = []
    class_names = label_encoder.classes_.tolist()

    for i, encoding in enumerate(face_encodings):
        encoding_2d = np.array(encoding).reshape(1, -1)

        probabilities = model.predict_proba(encoding_2d)[0]
        predicted_class_idx = np.argmax(probabilities)
        predicted_name = class_names[predicted_class_idx]
        max_confidence = float(probabilities[predicted_class_idx])

        probability_distribution = {}
        for j, class_name in enumerate(class_names):
            probability_distribution[class_name] = round(float(probabilities[j]), 6)

        sorted_distribution = dict(
            sorted(probability_distribution.items(), key=lambda x: x[1], reverse=True)
        )

        top, right, bottom, left = face_locations[i]

        access_threshold = 0.6
        access_granted = max_confidence >= access_threshold

        face_result = {
            "face_index": i,
            "bounding_box": {
                "top": top,
                "right": right,
                "bottom": bottom,
                "left": left
            },
            "best_match": {
                "employee_name": predicted_name,
                "confidence": round(max_confidence, 6)
            },
            "access_granted": access_granted,
            "confidence_threshold": access_threshold,
            "probability_distribution": sorted_distribution,
            "entropy": round(float(-np.sum(probabilities * np.log(probabilities + 1e-10))), 6),
            "top_3_matches": [
                {"employee_name": class_names[idx], "confidence": round(float(probabilities[idx]), 6)}
                for idx in np.argsort(probabilities)[::-1][:3]
            ]
        }

        results.append(face_result)

    return jsonify({
        "success": True,
        "message": f"Detected {len(results)} face(s) in the image.",
        "faces_detected": len(results),
        "known_employees": class_names,
        "num_known_employees": len(class_names),
        "faces": results,
        "timestamp": datetime.now().isoformat()
    }), 200


@app.route("/api/add_employee", methods=["POST"])
def add_employee():
    """
    Add a new employee photo to the training data directory.
    
    Accepts multipart form with:
    - 'name': employee name
    - 'image': photo file(s)
    """
    name = request.form.get("name")
    if not name:
        return jsonify({"success": False, "message": "Employee name is required."}), 400

    if "image" not in request.files:
        return jsonify({"success": False, "message": "At least one image is required."}), 400

    employee_dir = os.path.join(TRAINING_DATA_DIR, name)
    os.makedirs(employee_dir, exist_ok=True)

    saved_files = []
    files = request.files.getlist("image")

    for file in files:
        if file.filename:
            timestamp = datetime.now().strftime("%Y%m%d_%H%M%S_%f")
            ext = os.path.splitext(file.filename)[1] or ".jpg"
            filename = f"{timestamp}{ext}"
            filepath = os.path.join(employee_dir, filename)
            file.save(filepath)

            # Verify face is detectable
            try:
                img = Image.open(filepath)
                encs, _ = get_face_encoding(img)
                face_detected = encs is not None
            except Exception:
                face_detected = False

            saved_files.append({
                "filename": filename,
                "face_detected": face_detected
            })

    return jsonify({
        "success": True,
        "message": f"Added {len(saved_files)} photo(s) for employee '{name}'.",
        "employee_name": name,
        "files": saved_files,
        "note": "Remember to retrain the model via /api/train after adding new employees.",
        "timestamp": datetime.now().isoformat()
    }), 200


@app.route("/api/employees", methods=["GET"])
def list_employees():
    """List all known employees in the system."""
    global model, label_encoder

    if model is None or label_encoder is None:
        load_model()

    trained_employees = label_encoder.classes_.tolist() if label_encoder is not None else []

    directory_employees = {}
    if os.path.exists(TRAINING_DATA_DIR):
        for d in os.listdir(TRAINING_DATA_DIR):
            dir_path = os.path.join(TRAINING_DATA_DIR, d)
            if os.path.isdir(dir_path):
                photo_count = len([
                    f for f in os.listdir(dir_path)
                    if f.lower().endswith(('.jpg', '.jpeg', '.png', '.bmp', '.gif'))
                ])
                directory_employees[d] = photo_count

    return jsonify({
        "success": True,
        "trained_employees": trained_employees,
        "num_trained": len(trained_employees),
        "directory_employees": directory_employees,
        "model_loaded": model is not None,
        "timestamp": datetime.now().isoformat()
    }), 200


@app.route("/api/remove_employee", methods=["DELETE"])
def remove_employee():
    """Remove an employee from the training data."""
    data = request.get_json(silent=True) or {}
    name = data.get("name")

    if not name:
        return jsonify({"success": False, "message": "Employee name is required."}), 400

    employee_dir = os.path.join(TRAINING_DATA_DIR, name)
    if os.path.exists(employee_dir):
        import shutil
        shutil.rmtree(employee_dir)
        return jsonify({
            "success": True,
            "message": f"Removed employee '{name}'. Retrain the model to update.",
            "timestamp": datetime.now().isoformat()
        }), 200
    else:
        return jsonify({
            "success": False,
            "message": f"Employee '{name}' not found."
        }), 404


